def solve(n, k, l, s):
    # Count lowercase and uppercase letters
    lower_count = sum(1 for c in s if c.islower())
    upper_count = n - lower_count

    # Try to minimize lowercase letters by flipping them to uppercase
    def min_lower_after_k_ops(s, k, l):
        n = len(s)
        # diff[i] tells us how many operations cover position i
        diff = [0] * (n + 1)
        flipped = 0
        ops_used = 0

        for i in range(n):
            flipped += diff[i]
            # Position i is flipped if flipped is odd
            is_flipped = (flipped % 2 == 1)

            # Check if current char is lowercase (considering flips)
            if s[i].islower():
                if not is_flipped:
                    # Need to flip this position
                    if ops_used < k:
                        ops_used += 1
                        flipped += 1
                        if i + l <= n:
                            diff[i + l] -= 1
            else:
                if is_flipped:
                    # Uppercase became lowercase due to flip
                    # We might want to flip again to restore it
                    pass

        # Count remaining lowercase
        result = 0
        flipped = 0
        for i in range(n):
            flipped += diff[i]
            is_flipped = (flipped % 2 == 1)

            if s[i].islower():
                if not is_flipped:
                    result += 1
            else:
                if is_flipped:
                    result += 1

        return result
